<template><div class="workspace-page"><section class="page-intro"><div><p>日常健康数据</p><h2>日常测量</h2><span>单位由指标字典固定；一天可记录同一指标多次。</span></div><el-button type="primary" @click="openCreate">新增测量</el-button></section><el-card shadow="never"><el-table :data="items" v-loading="loading" empty-text="暂无测量"><el-table-column label="指标"><template #default="s"><strong>{{s.row.indicator?.name}}</strong></template></el-table-column><el-table-column label="数值"><template #default="s">{{s.row.value}} {{s.row.unit}}</template></el-table-column><el-table-column label="测量时间"><template #default="s">{{format(s.row.measured_at)}}</template></el-table-column><el-table-column label="操作" width="140"><template #default="s"><el-button link @click="openEdit(s.row)">编辑</el-button><el-button link type="danger" @click="remove(s.row)">删除</el-button></template></el-table-column></el-table></el-card>
<el-dialog v-model="visible" :title="form.id?'编辑测量':'新增测量'" width="520px"><el-form label-position="top"><el-form-item label="指标"><el-select v-model="form.indicator_dict_id" style="width:100%"><el-option v-for="i in allowed" :key="i.id" :label="`${i.name}（${i.unit}）`" :value="i.id"/></el-select></el-form-item><el-form-item label="数值"><el-input-number v-model="form.value" :min="0" :precision="2" :step="0.01" style="width:100%"/></el-form-item><el-form-item label="测量时间"><el-date-picker v-model="form.measured_at" type="datetime" value-format="YYYY-MM-DDTHH:mm:ssZ" style="width:100%"/></el-form-item></el-form><template #footer><el-button @click="visible=false">取消</el-button><el-button type="primary" :loading="saving" @click="save">保存</el-button></template></el-dialog></div></template>
<script setup>import{onMounted,reactive,ref}from"vue";import{ElMessage,ElMessageBox}from"element-plus";import{fetchIndicatorDicts}from"../api/indicators";import{createMeasurement,deleteMeasurement,fetchMeasurements,updateMeasurement}from"../api/health";const items=ref([]),allowed=ref([]),loading=ref(false),saving=ref(false),visible=ref(false),form=reactive({id:null,indicator_dict_id:null,value:null,measured_at:null});const format=v=>new Date(v).toLocaleString("zh-CN",{hour12:false});async function load(){loading.value=true;try{const[a,b]=await Promise.all([fetchMeasurements(),fetchIndicatorDicts()]);items.value=a.data.items||[];allowed.value=(b.data.items||[]).filter(i=>i.allow_self_measurement)}finally{loading.value=false}}function openCreate(){Object.assign(form,{id:null,indicator_dict_id:allowed.value[0]?.id||null,value:null,measured_at:new Date().toISOString()});visible.value=true}function openEdit(i){Object.assign(form,{id:i.id,indicator_dict_id:i.indicator_dict_id,value:i.value,measured_at:i.measured_at});visible.value=true}async function save(){saving.value=true;try{const payload={indicator_dict_id:form.indicator_dict_id,value:form.value,measured_at:form.measured_at};form.id?await updateMeasurement(form.id,payload):await createMeasurement(payload);ElMessage.success("测量已保存");visible.value=false;await load()}catch(e){ElMessage.error(e?.response?.data?.message||"保存失败")}finally{saving.value=false}}async function remove(i){try{await ElMessageBox.confirm("确认删除这条原始测量？","删除测量",{type:"warning"});await deleteMeasurement(i.id);await load()}catch(e){if(e!=="cancel"&&e!=="close")ElMessage.error("删除失败")}}onMounted(load);</script>
